sql:
SELECT full_title
FROM journals
ORDER BY frequency DESC;

SELECT ranking_id, journal_id, metric
FROM journal_rankings
WHERE ranking > 0;

SELECT full_title
FROM journals
ORDER BY full_title ASC;

SELECT AVG(accesses) AS average_accesses
FROM (
    SELECT user_id, COUNT(access_id) AS accesses
    FROM access_logs
    GROUP BY user_id
);

